Extensions.ExtractScript:
param(
    [xml] $Document
);

foreach( $file in $Document.unattend.Extensions.File ) {
    $path = [System.Environment]::ExpandEnvironmentVariables( $file.GetAttribute( 'path' ) );
    mkdir -Path( $path | Split-Path -Parent ) -ErrorAction 'SilentlyContinue';
    $encoding = switch( [System.IO.Path]::GetExtension( $path ) ) {
        { $_ -in '.ps1', '.xml' } { [System.Text.Encoding]::UTF8; }
        { $_ -in '.reg', '.vbs', '.js' } { [System.Text.UnicodeEncoding]::new( $false, $true ); }
        default { [System.Text.Encoding]::Default; }
    };
    $bytes = $encoding.GetPreamble() + $encoding.GetBytes( $file.InnerText.Trim() );
    [System.IO.File]::WriteAllBytes( $path, $bytes );
}

Extensions.File:
$selectors = @(
	'Microsoft.Microsoft3DViewer';
	'Microsoft.BingSearch';
	'Microsoft.WindowsCamera';
	'Clipchamp.Clipchamp';
	'Microsoft.Copilot';
	'Microsoft.549981C3F5F10';
	'Microsoft.Windows.DevHome';
	'MicrosoftCorporationII.MicrosoftFamily';
	'Microsoft.WindowsFeedbackHub';
	'Microsoft.Edge.GameAssist';
	'Microsoft.GetHelp';
	'Microsoft.Getstarted';
	'microsoft.windowscommunicationsapps';
	'Microsoft.WindowsMaps';
	'Microsoft.MixedReality.Portal';
	'Microsoft.BingNews';
	'Microsoft.MicrosoftOfficeHub';
	'Microsoft.Office.OneNote';
	'Microsoft.OutlookForWindows';
	'Microsoft.People';
	'Microsoft.SkypeApp';
	'Microsoft.MicrosoftSolitaireCollection';
	'Microsoft.MicrosoftStickyNotes';
	'MicrosoftTeams';
	'MSTeams';
	'Microsoft.Todos';
	'Microsoft.WindowsSoundRecorder';
	'Microsoft.Wallet';
	'Microsoft.BingWeather';
	'Microsoft.YourPhone';
);
$getCommand = {
  Get-AppxProvisionedPackage -Online;
};
$filterCommand = {
  $_.DisplayName -eq $selector;
};
$removeCommand = {
  [CmdletBinding()]
  param(
    [Parameter( Mandatory, ValueFromPipeline )]
    $InputObject
  );
  process {
    $InputObject | Remove-AppxProvisionedPackage -AllUsers -Online -ErrorAction 'Continue';
  }
};
$type = 'Package';
$logfile = 'C:\Windows\Setup\Scripts\RemovePackages.log';
& {
	$installed = & $getCommand;
	foreach( $selector in $selectors ) {
		$result = [ordered] @{
			Selector = $selector;
		};
		$found = $installed | Where-Object -FilterScript $filterCommand;
		if( $found ) {
			$result.Output = $found | & $removeCommand;
			if( $? ) {
				$result.Message = "$type removed.";
			} else {
				$result.Message = "$type not removed.";
				$result.Error = $Error[0];
			}
		} else {
			$result.Message = "$type not installed.";
		}
		$result | ConvertTo-Json -Depth 3 -Compress;
	}
} *>&1 | Out-String -Width 1KB -Stream >> $logfile;

$selectors = @(
	'Language.Handwriting';
	'MathRecognizer';
	'OneCoreUAP.OneSync';
	'Language.Speech';
	'Language.TextToSpeech';
	'App.StepsRecorder';
	'Hello.Face.18967';
	'Hello.Face.Migration.18967';
	'Hello.Face.20134';
);
$getCommand = {
  Get-WindowsCapability -Online | Where-Object -Property 'State' -NotIn -Value @(
    'NotPresent';
    'Removed';
  );
};
$filterCommand = {
  ($_.Name -split '~')[0] -eq $selector;
};
$removeCommand = {
  [CmdletBinding()]
  param(
    [Parameter( Mandatory, ValueFromPipeline )]
    $InputObject
  );
  process {
    $InputObject | Remove-WindowsCapability -Online -ErrorAction 'Continue';
  }
};
$type = 'Capability';
$logfile = 'C:\Windows\Setup\Scripts\RemoveCapabilities.log';
& {
	$installed = & $getCommand;
	foreach( $selector in $selectors ) {
		$result = [ordered] @{
			Selector = $selector;
		};
		$found = $installed | Where-Object -FilterScript $filterCommand;
		if( $found ) {
			$result.Output = $found | & $removeCommand;
			if( $? ) {
				$result.Message = "$type removed.";
			} else {
				$result.Message = "$type not removed.";
				$result.Error = $Error[0];
			}
		} else {
			$result.Message = "$type not installed.";
		}
		$result | ConvertTo-Json -Depth 3 -Compress;
	}
} *>&1 | Out-String -Width 1KB -Stream >> $logfile;

$selectors = @(
	'Recall';
);
$getCommand = {
  Get-WindowsOptionalFeature -Online | Where-Object -Property 'State' -NotIn -Value @(
    'Disabled';
    'DisabledWithPayloadRemoved';
  );
};
$filterCommand = {
  $_.FeatureName -eq $selector;
};
$removeCommand = {
  [CmdletBinding()]
  param(
    [Parameter( Mandatory, ValueFromPipeline )]
    $InputObject
  );
  process {
    $InputObject | Disable-WindowsOptionalFeature -Online -Remove -NoRestart -ErrorAction 'Continue';
  }
};
$type = 'Feature';
$logfile = 'C:\Windows\Setup\Scripts\RemoveFeatures.log';
& {
	$installed = & $getCommand;
	foreach( $selector in $selectors ) {
		$result = [ordered] @{
			Selector = $selector;
		};
		$found = $installed | Where-Object -FilterScript $filterCommand;
		if( $found ) {
			$result.Output = $found | & $removeCommand;
			if( $? ) {
				$result.Message = "$type removed.";
			} else {
				$result.Message = "$type not removed.";
				$result.Error = $Error[0];
			}
		} else {
			$result.Message = "$type not installed.";
		}
		$result | ConvertTo-Json -Depth 3 -Compress;
	}
} *>&1 | Out-String -Width 1KB -Stream >> $logfile;

# ========================================================================= # Имя файла: system-logon-init.ps1 # Назначение: Бескомпромиссная блокировка рекламы, телеметрии, Outlook, Яндекс.Музыки, Edge и настройка UI # Этап: System Logon / Pre-OOBE (Выполняется от имени SYSTEM) # Логирование: Документы дефолтного пользователя # =========================================================================
Set-StrictMode -Version Latest $ErrorActionPreference = 'Stop' $ProgressPreference = 'SilentlyContinue'
# Настройка логирования в C:\Users\Default\Documents $LogDir = "C:\Users\Default\Documents" if (-not (Test-Path $LogDir)) { New-Item -ItemType Directory -Force -Path $LogDir | Out-Null } Start-Transcript -Path (Join-Path $LogDir "System_Logon_Initialization.log") -Append
try { Write-Host "=========================================================" Write-Host " СТАРТ РАСШИРЕННОЙ ОПТИМИЗАЦИИ СИСТЕМЫ (SYSTEM CONTEXT)" Write-Host "========================================================="
# ---------------------------------------------------- # 1. ГЛОБАЛЬНЫЕ ПОЛИТИКИ (HKLM) ПРОТИВ РЕКЛАМЫ И МУСОРА # ---------------------------------------------------- Write-Host ">>> Настройка глобальных политик CloudContent и виджетов..." $CloudContentPath = "HKLM:\SOFTWARE\Policies\Microsoft\Windows\CloudContent" if (-not (Test-Path $CloudContentPath)) { New-Item -Path $CloudContentPath -Force | Out-Null } Set-ItemProperty -Path $CloudContentPath -Name "DisableWindowsConsumerFeatures" -Value 1 -Type DWord -Force Set-ItemProperty -Path $CloudContentPath -Name "DisableWindowsSpotlightFeatures" -Value 1 -Type DWord -Force Set-ItemProperty -Path $CloudContentPath -Name "DisableThirdPartySuggestions" -Value 1 -Type DWord -Force
# Отключение виджетов (Feeds) на панели задач для всех $Feeds = "HKLM:\SOFTWARE\Policies\Microsoft\Windows\Windows Feeds" if (!(Test-Path $Feeds)) { New-Item -Path $Feeds -Force | Out-Null } Set-ItemProperty -Path $Feeds -Name "EnableFeeds" -Value 0 -Type DWord -Force
Write-Host ">>> Глубокая конфигурация глобального ContentDeliveryManager..." $CdmPathHKLM = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\ContentDeliveryManager" if (-not (Test-Path $CdmPathHKLM)) { New-Item -Path $CdmPathHKLM -Force | Out-Null }
$CdmTweaks = @{ "SilentInstalledAppsEnabled" = 0 "ContentDeliveryAllowed" = 0 "OemPreInstalledAppsEnabled" = 0 "PreInstalledAppsEnabled" = 0 "PreInstalledAppsReady" = 0 "SubscribedContentEnabled" = 0 "SystemPaneSuggestionsEnabled" = 0 "SubscribedContent-310093Enabled" = 0 "SubscribedContent-338387Enabled" = 0 "SubscribedContent-338388Enabled" = 0 "SubscribedContent-338389Enabled" = 0 "SubscribedContent-353475Enabled" = 0 } foreach ($Key in $CdmTweaks.Keys) { Set-ItemProperty -Path $CdmPathHKLM -Name $Key -Value $CdmTweaks[$Key] -Type DWord -Force }
# ---------------------------------------------------- # 1.5. УКРОЩЕНИЕ MICROSOFT EDGE И ОБЩЕГО РАБОЧЕГО СТОЛА # ---------------------------------------------------- Write-Host ">>> Полная блокировка Microsoft Edge и очистка общего стола..."
# Политики HKLM для Edge $EdgePol = "HKLM:\SOFTWARE\Policies\Microsoft\Edge" if (!(Test-Path $EdgePol)) { New-Item -Path $EdgePol -Force | Out-Null } $EdgeSettings = @{ "HideFirstRunExperience" = 1 "CreateDesktopShortcut" = 0 "WelcomePageOnFirstLaunchEnabled" = 0 "StartupBoostEnabled" = 0 "BackgroundModeEnabled" = 0 "AllowPrelaunch" = 0 "AutoImportAtFirstRun" = 0 "HubsSidebarEnabled" = 0 } foreach ($name in $EdgeSettings.Keys) { Set-ItemProperty -Path $EdgePol -Name $name -Value $EdgeSettings[$name] -Type DWord -Force }
# Отключение служб обновления Edge $EdgeServices = @("edgeupdate", "edgeupdatem", "MicrosoftEdgeElevationService") foreach ($svc in $EdgeServices) { if (Get-Service -Name $svc -ErrorAction SilentlyContinue) { Stop-Service -Name $svc -Force -ErrorAction SilentlyContinue Set-Service -Name $svc -StartupType Disabled } }
# Удаление задач Edge в планировщике Get-ScheduledTask -TaskPath "\" -ErrorAction SilentlyContinue | Where-Object { $_.TaskName -like "*MicrosoftEdge*" } | Disable-ScheduledTask -ErrorAction SilentlyContinue
# Обход Active Setup (предотвращает создание ярлыков Edge при входе любого пользователя) $ActiveSetup = "HKLM:\SOFTWARE\Microsoft\Active Setup\Installed Components" Get-ChildItem $ActiveSetup -ErrorAction SilentlyContinue | Where-Object { (Get-ItemProperty $_.PsPath -ErrorAction SilentlyContinue).StubPath -like "*MicrosoftEdge*" } | ForEach-Object { Set-ItemProperty -Path $_.PsPath -Name "StubPath" -Value "" -Force }
# Удаление ярлыков Edge и Teams с общего Рабочего стола Get-ChildItem -Path "$env:PUBLIC\Desktop" -Filter "*.lnk" | Where-Object { $_.Name -match "Edge|Teams" } | Remove-Item -Force -ErrorAction SilentlyContinue
# Создание кастомного макета Панели задач (XML) сразу в папке Default User Write-Host ">>> Создание чистого XML макета Панели задач..." $LayoutXml = @" <LayoutModificationTemplate xmlns="http://schemas.microsoft.com/Start/2014/LayoutModification" xmlns:defaultlayout="http://schemas.microsoft.com/Start/2014/FullDefaultLayout" xmlns:start="http://schemas.microsoft.com/Start/2014/StartLayout" xmlns:taskbar="http://schemas.microsoft.com/Start/2014/TaskbarLayout" Version="1"> <LayoutOptions StartTileGroupCellWidth="6" /> <DefaultLayoutOverride><StartLayoutCollection><defaultlayout:StartLayout GroupCellWidth="6" /></StartLayoutCollection></DefaultLayoutOverride> <CustomTaskbarLayoutCollection PinListPlacement="Replace"> <defaultlayout:TaskbarLayout><taskbar:TaskbarPinList> <taskbar:DesktopApp DesktopApplicationID="Microsoft.Windows.Explorer" /> </taskbar:TaskbarPinList></defaultlayout:TaskbarLayout> </CustomTaskbarLayoutCollection> </LayoutModificationTemplate> "@ $D_Shell = "C:\Users\Default\AppData\Local\Microsoft\Windows\Shell" if (!(Test-Path $D_Shell)) { New-Item -Path $D_Shell -ItemType Directory -Force | Out-Null } $LayoutXml | Out-File -FilePath "$D_Shell\LayoutModification.xml" -Encoding UTF8 -Force
# ---------------------------------------------------- # 2. ЖЕСТКИЙ АНТИДОТ ПРОТИВ ОБХОДА НОВОГО OUTLOOK (Фишка 2025/2026 гг.) # ---------------------------------------------------- Write-Host ">>> Аппаратное отключение OOBE-апдейтера для Outlook..." $USchedulerPath = "HKLM:\SOFTWARE\Microsoft\WindowsUpdate\Orchestrator\UScheduler_Oobe" if (-not (Test-Path $USchedulerPath)) { New-Item -Path $USchedulerPath -Force | Out-Null } Set-ItemProperty -Path $USchedulerPath -Name "BlockedOobeUpdaters" -Value '["MS_Outlook"]' -Type String -Force
$OutlookUpdateTask = "HKLM:\SOFTWARE\Microsoft\WindowsUpdate\Orchestrator\UScheduler_Oobe\OutlookUpdate" if (Test-Path $OutlookUpdateTask) { Remove-Item -Path $OutlookUpdateTask -Recurse -Force }
$OutlookPolicyPath = "HKLM:\SOFTWARE\Policies\Microsoft\Office\16.0\Outlook\Options\General" if (-not (Test-Path $OutlookPolicyPath)) { New-Item -Path $OutlookPolicyPath -Force | Out-Null } Set-ItemProperty -Path $OutlookPolicyPath -Name "HideNewOutlookToggle" -Value 1 -Type DWord -Force
$OutlookPrefPath = "HKLM:\SOFTWARE\Policies\Microsoft\Office\16.0\Outlook\Preferences" if (-not (Test-Path $OutlookPrefPath)) { New-Item -Path $OutlookPrefPath -Force | Out-Null } Set-ItemProperty -Path $OutlookPrefPath -Name "NewOutlookMigrationUserSetting" -Value 0 -Type DWord -Force
# ---------------------------------------------------- # 3. НАСТРОЙКА ДЕФОЛТНОГО ПРОФИЛЯ ПОЛЬЗОВАТЕЛЯ (NTUSER.DAT) # ---------------------------------------------------- Write-Host ">>> Монтирование дефолтного куста реестра для настройки профилей..." $DefaultHivePath = "C:\Users\Default\NTUSER.DAT"
if (-not (Test-Path "HKLM:\TargetUser")) { reg load "HKLM\TargetUser" $DefaultHivePath | Out-Null }
$PathsToTweak = @( "HKLM:\TargetUser\Software\Microsoft\Windows\CurrentVersion\ContentDeliveryManager", "HKLM:\TargetUser\Software\Policies\Microsoft\Windows\CloudContent", "HKLM:\TargetUser\Software\Policies\Microsoft\Edge", "HKLM:\TargetUser\Software\Microsoft\Windows\CurrentVersion\Search", "HKLM:\TargetUser\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced", "HKLM:\TargetUser\Software\Microsoft\Windows\CurrentVersion\Explorer\HideDesktopIcons\NewStartPanel" ) foreach ($Path in $PathsToTweak) { if (-not (Test-Path $Path)) { New-Item -Path $Path -Force | Out-Null } }
# Применяем весь спектр блокировок рекламы и автоустановок Set-ItemProperty -Path "HKLM:\TargetUser\Software\Policies\Microsoft\Windows\CloudContent" -Name "DisableWindowsConsumerFeatures" -Value 1 -Type DWord -Force Set-ItemProperty -Path "HKLM:\TargetUser\Software\Policies\Microsoft\Windows\CloudContent" -Name "DisableWindowsSpotlightFeatures" -Value 1 -Type DWord -Force foreach ($Key in $CdmTweaks.Keys) { Set-ItemProperty -Path "HKLM:\TargetUser\Software\Microsoft\Windows\CurrentVersion\ContentDeliveryManager" -Name $Key -Value $CdmTweaks[$Key] -Type DWord -Force }
# Настройки Edg

# ============================================================================== # Проверка прав администратора # ============================================================================== $isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
if (-not $isAdmin) { # Перезапуск с правами админа и скрытием черного окна консоли (-WindowStyle Hidden) Start-Process powershell.exe -ArgumentList "-NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"$PSCommandPath`"" -Verb RunAs exit }
# ============================================================================== # Функции и интерфейс (WPF) # ============================================================================== Add-Type -AssemblyName PresentationFramework
# XAML-дизайн окна (темная тема, увеличена высота до 340 для вмещения текста) [xml]$xaml = @" <Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml" WindowStyle="None" AllowsTransparency="True" Background="#151720" WindowStartupLocation="CenterScreen" Width="650" Height="340" Topmost="True"> <Border BorderBrush="#4C7BB0" BorderThickness="1" CornerRadius="0"> <Grid Margin="30,25,30,25"> <Grid.RowDefinitions> <RowDefinition Height="Auto"/> <RowDefinition Height="Auto"/> <RowDefinition Height="*"/> <RowDefinition Height="Auto"/> <RowDefinition Height="Auto"/> </Grid.RowDefinitions>
<Grid Grid.Row="0"> <TextBlock Text="ЗАГРУЗЧИК АВТОМАТИЧЕСКОЙ НАСТРОЙКИ" Foreground="#7A9EEB" FontSize="18" FontWeight="Bold" VerticalAlignment="Center" />
<!-- Кастомная кнопка закрытия (Крестик сверху) --> <Button Name="BtnCloseTop" Content="✕" HorizontalAlignment="Right" VerticalAlignment="Center" Width="30" Height="30" FontSize="16" Cursor="Hand" ToolTip="Закрыть"> <Button.Template> <ControlTemplate TargetType="Button"> <Border Name="Border" BorderBrush="#4C7BB0" BorderThickness="1" Background="Transparent"> <TextBlock Text="{TemplateBinding Content}" HorizontalAlignment="Center" VerticalAlignment="Center" Margin="0,0,0,2"/> </Border> <ControlTemplate.Triggers> <Trigger Property="IsMouseOver" Value="True"> <Setter TargetName="Border" Property="Background" Value="#4C7BB0" /> <Setter Property="Foreground" Value="White" /> </Trigger> <Trigger Property="IsMouseOver" Value="False"> <Setter Property="Foreground" Value="#7A9EEB" /> </Trigger> </ControlTemplate.Triggers> </ControlTemplate> </Button.Template> </Button> </Grid>
<Rectangle Grid.Row="1" Height="1" Fill="#4C7BB0" Margin="0,20,0,25"/>
<TextBlock Name="TxtMessage" Grid.Row="2" Foreground="White" FontSize="15" TextWrapping="Wrap" LineHeight="24" VerticalAlignment="Top" />
<TextBlock Name="TxtNote" Grid.Row="3" Foreground="#888888" FontSize="12" TextWrapping="Wrap" HorizontalAlignment="Center" Margin="0,10,0,0"/>
<!-- Большая плоская кнопка ВЫХОД снизу --> <Button Name="BtnExit" Grid.Row="4" Content="ВЫХОД" Height="40" Margin="0,15,0,0" Cursor="Hand" FontWeight="Bold" FontSize="13" Foreground="White"> <Button.Template> <ControlTemplate TargetType="Button"> <!-- Цвет фона как на вашем скриншоте --> <Border Name="Border" Background="#353746" BorderThickness="0"> <TextBlock Text="{TemplateBinding Content}" HorizontalAlignment="Center" VerticalAlignment="Center" Margin="0,0,0,1"/> </Border> <ControlTemplate.Triggers> <Trigger Property="IsMouseOver" Value="True"> <!-- Подсветка при наведении --> <Setter TargetName="Border" Property="Background" Value="#4A4D62" /> </Trigger> </ControlTemplate.Triggers> </ControlTemplate> </Button.Template> </Button> </Grid> </Border> </Window> "@
$reader = (New-Object System.Xml.XmlNodeReader $xaml) $window = [System.Windows.Markup.XamlReader]::Load($reader)
$txtMessage = $window.FindName("TxtMessage") $txtNote = $window.FindName("TxtNote") $btnCloseTop = $window.FindName("BtnCloseTop") $btnExit = $window.FindName("BtnExit")
# Обработчики закрытия на обе кнопки $btnCloseTop.Add_Click({ $window.Close(); exit }) $btnExit.Add_Click({ $window.Close(); exit })
# Функция проверки интернета function Test-Internet { try { $request = [System.Net.WebRequest]::Create("http://clients3.google.com/generate_204") $request.Timeout = 3000 $response = $request.GetResponse() $response.Close() return $true } catch { return $false } }
# Пути для создания файлов на Рабочем столе $desktopPath = [Environment]::GetFolderPath('Desktop') $loaderPs1Path = Join-Path $desktopPath "loader.ps1" $loaderCmdPath = Join-Path $desktopPath "Loader.cmd"
# Надежное определение пути текущего запущенного скрипта $currentScriptPath = $PSCommandPath if ([string]::IsNullOrWhiteSpace($currentScriptPath)) { $currentScriptPath = $MyInvocation.MyCommand.Definition }
# ============================================================================== # Логика: Интернет ОТСУТСТВУЕТ # ============================================================================== if (-not (Test-Internet)) { if (Test-Path $currentScriptPath) { # 1. Копируем сам скрипт (.ps1) Copy-Item -Path $currentScriptPath -Destination $loaderPs1Path -Force
# Делаем файл loader.ps1 скрытым $ps1File = Get-Item -Path $loaderPs1Path -Force $ps1File.Attributes = $ps1File.Attributes -bor [System.IO.FileAttributes]::Hidden
# 2. Создаем запускатор Loader.cmd (внутри скрипт запускает powershell скрытно) $cmdContent = "@echo off`r`nPowerShell.exe -NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"%~dp0loader.ps1`"" Set-Content -Path $loaderCmdPath -Value $cmdContent -Force }
# Настраиваем текст окна $txtMessage.Text = "Соединение с интернетом не обнаружено!`n`nПожалуйста, подключитесь к сети (включите Wi-Fi или вставьте Ethernet-кабель) и запустите появившийся файл «Loader.cmd» с Рабочего стола." $txtMessage.Foreground = "#E57373" # Красный оттенок
# Очищаем нижнюю надпись, кнопка ВЫХОД остается видимой $txtNote.Text = ""
# Показываем окно и ждем закрытия $window.ShowDialog() | Out-Null exit }
# ============================================================================== # Логика: Интернет ЕСТЬ # ==============================================================================
# Удаляем временные файлы с рабочего стола, так как они больше не нужны (интернет есть) if (Test-Path $loaderPs1Path) { Remove-Item -Path $loaderPs1Path -Force -ErrorAction SilentlyContinue } if (Test-Path $loaderCmdPath) { Remove-Item -Path $loaderCmdPath -Force -ErrorAction SilentlyContinue }
# Настраиваем окно под загрузку (прячем крестик сверху и кнопку снизу) $btnCloseTop.Visibility = "Hidden" $btnExit.Visibility = "Collapsed" # Схлопываем кнопку ВЫХОД, чтобы она не занимала место
$txtMessage.Text = "✓ Соединение установлено.`n`nИдет скачивание репозитория и распаковка файлов...`nПожалуйста, подождите." $txtMessage.Foreground = "#81C784" # Зеленый оттенок $txtNote.Text = "Пожалуйста, не закрывайте это окно до завершения скачивания."
# Показываем окно асинхронно $window.Show() $window.Dispatcher.Invoke([Action]{}, [System.Windows.Threading.DispatcherPriority]::Background)
# --- ПРОЦЕСС ЗАГРУЗКИ --- try { [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
$targetBasePath = "C:\Windows\Setup" $finalScriptsPath = Join-Path -Path $targetBasePath -ChildPath "Scripts" $zipPath = Join-Path -Path $env:TEMP -ChildPath "powershell-scripts.zip" $tempExtractPath = Join-Path -Path $env:TEMP -ChildPath "temp-repo-extract"
if (-not (Test-Path $targetBasePath)) { New-Item -Path $targetBasePath -ItemType Directory -Force | Out-Null } if (Test-Path $tempExtractPath) { Remove-Item -Path $tempExtractPath -Recurse -Force } if (Test-Path $finalScriptsPath) { Remove-Item -Path $finalScriptsPath -Recurse -Force }
$urlMain = "https://github.com/AgentSharik/powershell-scripts/archive/refs/heads/main.zip" $urlMaster = "https://github.com/AgentSharik/powershell-scripts/archive/refs/heads/master.zip"
try { Invoke-WebRequest -Uri $urlMain -OutFile $zipPath -ErrorAction Stop } catch { Invoke-WebRequest -Uri $urlMaster -OutFile $zipPath }
Expand-Archive -Path $zipPath -DestinationPath $tempExtractPath -Force
$repoFolder = Get-ChildItem -Path $tempExtractPath -Directory | Select-Object -First 1 $extractedScriptsFolder = Join-Path -Path $repoFolder.FullName -ChildPath "Scripts\Scripts for Custom Windows (with Autounattend)"
if (Test-Path $extractedScriptsFolder) { Move-Item -Path $extractedScriptsFolder -Destination $finalScriptsPath -Force
# Исправление кодировки (BOM) $psFiles = Get-ChildItem -Path $finalScriptsPath -Filter "*.ps1" -Recurse $utf8Bom = New-Object System.Text.UTF8Encoding($true) foreach ($file in $psFiles) { $content = [System.IO.File]::ReadAllText($file.FullName, [System.Text.Encoding]::UTF8) [System.IO.File]::WriteAllText($file.FullName, $content, $utf8Bom) }
$managerScript = Join-Path -Path $finalScriptsPath -ChildPath "manager.ps1" if (Test-Path $managerScript) { # Запускаем основной скрипт Start-Process powershell.exe -ArgumentList "-ExecutionPolicy Bypass -NoExit -File `"$managerScript`"" } }
# Очистка Temp if (Test-Path $zipPath) { Remove-Item -Path $zipPath -Force } if (Test-Path $tempExtractPath) { Remove-Item -Path $tempExtractPath -Recurse -Force }
} catch { Write-Error "Ошибка при загрузке: $($_.Exception.Message)" Start-Sleep -Seconds 5 } finally { $window.Close() }

$scripts = @(
	{
		reg.exe add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\OOBE" /v BypassNRO /t REG_DWORD /d 1 /f;
	};
	{
		Remove-Item -LiteralPath 'Registry::HKLM\Software\Microsoft\WindowsUpdate\Orchestrator\UScheduler_Oobe\DevHomeUpdate' -Force -ErrorAction 'SilentlyContinue';
	};
	{
		Remove-Item -LiteralPath 'C:\Users\Default\AppData\Roaming\Microsoft\Windows\Start Menu\Programs\OneDrive.lnk', 'C:\Windows\System32\OneDriveSetup.exe', 'C:\Windows\SysWOW64\OneDriveSetup.exe' -ErrorAction 'Continue';
	};
	{
		Remove-Item -LiteralPath 'Registry::HKLM\Software\Microsoft\WindowsUpdate\Orchestrator\UScheduler_Oobe\OutlookUpdate' -Force -ErrorAction 'SilentlyContinue';
